def websocket_accept_key(key):
    try:
        import ubinascii
        import uhashlib
        magic = '258EAFA5-E914-47DA-95CA-C5AB0DC85B11'
        sha1 = uhashlib.sha1((key + magic).encode())
        digest = sha1.digest()
        return ubinascii.b2a_base64(digest)[:-1].decode()
    except Exception:
        return ''

def ws_send(sock, message):
    if isinstance(message, str):
        payload = message.encode()
    else:
        payload = message
    length = len(payload)
